{
  "level": "B1",
  "intro": "W tym temacie poznasz <strong>Past Continuous Passive</strong>: jak tworzyć tę formę i kiedy używać jej do opisu procesu trwającego w przeszłości.",
  "rules": [
    {
      "label": "Wzór",
      "color": "emerald",
      "text": "<strong>subject + was / were being + V3</strong>:",
      "example": "The house was being painted when I arrived."
    },
    {
      "label": "Przeczenie",
      "color": "rose",
      "text": "<strong>subject + was / were not being + V3</strong>:",
      "example": "The report was not being written at that time."
    },
    {
      "label": "Pytanie",
      "color": "blue",
      "text": "<strong>Was / Were + subject + being + V3?</strong>:",
      "example": "Was the project being developed?"
    }
  ]
}

{
  "title": "1. Budowa Past Continuous Passive",
  "intro": "Formy <strong>was</strong> i <strong>were</strong> dobieramy do podmiotu, a <strong>being</strong> pozostaje niezmienne:",
  "items": [
    {
      "label": "I / He / She / It",
      "title": "was being + V3",
      "subtitle": "The car was being repaired."
    },
    {
      "label": "You / We / They",
      "title": "were being + V3",
      "subtitle": "The documents were being checked."
    },
    {
      "label": "Liczba pojedyncza",
      "title": "was being + V3",
      "subtitle": "The house was being built."
    },
    {
      "label": "Uwaga",
      "title": "being jest stałe",
      "subtitle": "W tej formie <strong>being</strong> zawsze stoi przed V3."
    }
  ]
}

{
    "title": "2. Zdania twierdzące",
    "sections": [
        {
            "label": "Struktura",
            "color": "emerald",
            "description": "Kolejność słów: <strong>podmiot + był/był + istota + V3 (+ według agenta)</strong>",
            "examples": [
                {
                    "en": "The house was being painted when I arrived.",
                    "ua": "Kiedy przyjechałem, dom był malowany."
                },
                {
                    "en": "The documents were being prepared all morning.",
                    "ua": "Dokumenty były przygotowywane przez cały ranek."
                },
                {
                    "en": "The car was being repaired at 5 PM.",
                    "ua": "Samochód został naprawiony o godzinie 17:00."
                },
                {
                    "en": "The rooms were being cleaned by the staff.",
                    "ua": "Pokoje były sprzątane przez personel."
                }
            ]
        },
        {
            "label": "Ciągłe działanie w przeszłości",
            "color": "sky",
            "description": "W przypadku działań, które <strong>kontynuowały w określonym momencie</strong>:",
            "examples": [
                {
                    "en": "At 3 PM, the meeting was being held.",
                    "ua": "O godzinie 15:00 odbyło się spotkanie."
                },
                {
                    "en": "The road was being repaired all day.",
                    "ua": "Droga była naprawiana przez cały dzień."
                },
                {
                    "en": "The project was being discussed when he called.",
                    "ua": "Kiedy zadzwonił, projekt był omawiany."
                }
            ]
        }
    ]
}

{
    "title": "3. Kiedy używać czasu Past Continuous Passive?",
    "sections": [
        {
            "label": "Akcja w chwili przeszłej",
            "color": "emerald",
            "description": "W przypadku działań, które <strong>trwały w pewnym momencie w przeszłości</strong>:",
            "examples": [
                {
                    "en": "At 8 AM, breakfast was being served.",
                    "ua": "Śniadanie podano o godzinie 8:00."
                },
                {
                    "en": "The building was being renovated last summer.",
                    "ua": "Budynek został odnowiony latem ubiegłego roku."
                },
                {
                    "en": "The reports were being prepared yesterday evening.",
                    "ua": "Raporty zostały przygotowane wczoraj wieczorem."
                }
            ]
        },
        {
            "label": "Działania równoległe",
            "color": "blue",
            "description": "Kiedy jedno działanie <strong>przerwało inne trwające</strong>:",
            "examples": [
                {
                    "en": "The car was being washed when it started to rain.",
                    "ua": "Samochód był myty, kiedy zaczął padać deszcz."
                },
                {
                    "en": "The dinner was being cooked when the guests arrived.",
                    "ua": "Kiedy przyszli goście, przygotowywano kolację."
                },
                {
                    "en": "The document was being printed when the power went out.",
                    "ua": "Dokument został wydrukowany, gdy światło było wyłączone."
                }
            ]
        },
        {
            "label": "Czas trwania procesu",
            "color": "amber",
            "description": "Aby podkreślić <strong>czas trwania procesu</strong>:",
            "examples": [
                {
                    "en": "The house was being built for two years.",
                    "ua": "Dom budowany był dwa lata."
                },
                {
                    "en": "The project was being developed throughout the year.",
                    "ua": "Projekt powstał w ciągu roku."
                },
                {
                    "en": "The investigation was being conducted all week.",
                    "ua": "Śledztwo trwało cały tydzień."
                }
            ]
        }
    ]
}

{
    "title": "4. Zdania przeczące",
    "sections": [
        {
            "label": "Struktura",
            "color": "rose",
            "description": "Dodaj <strong>nie</strong> po było/było: <strong>podmiot + był/był + nie + był + V3</strong>",
            "examples": [
                {
                    "en": "The report was not being written at that time.",
                    "ua": "Raport nie był wówczas pisany."
                },
                {
                    "en": "The rooms were not being cleaned yesterday.",
                    "ua": "Wczoraj pokoje nie były sprzątane."
                },
                {
                    "en": "The problem was not being addressed.",
                    "ua": "Problem nie został rozwiązany."
                },
                {
                    "en": "The orders were not being processed.",
                    "ua": "Zamówienie nie zostało zrealizowane."
                }
            ]
        },
        {
            "label": "Skrócone formy",
            "color": "amber",
            "description": "Potocznie: <strong>nie byłem/nie byłem</strong>",
            "examples": [
                {
                    "en": "The car wasn't being repaired yesterday.",
                    "ua": "Wczoraj samochód nie został naprawiony."
                },
                {
                    "en": "The packages weren't being delivered.",
                    "ua": "Przesyłki nie zostały dostarczone."
                },
                {
                    "en": "The issue wasn't being investigated.",
                    "ua": "Sprawa nie została zbadana."
                }
            ]
        }
    ]
}

{
    "title": "5. Zdania pytające",
    "sections": [
        {
            "label": "Pytania yes/no",
            "color": "blue",
            "description": "Na pierwszym miejscu jest <strong>Było/było</strong>: <strong>Było/było + podmiot + istota + V3?</strong>",
            "examples": [
                {
                    "en": "Was the house being painted?",
                    "ua": "Czy dom był malowany?"
                },
                {
                    "en": "Were the documents being checked?",
                    "ua": "Czy dokumenty zostały sprawdzone?"
                },
                {
                    "en": "Was the project being developed?",
                    "ua": "Czy projekt został opracowany?"
                },
                {
                    "en": "Were they being interviewed?",
                    "ua": "Czy przeprowadzono z nimi wywiad?"
                }
            ]
        },
        {
            "label": "Jakie pytanie",
            "color": "sky",
            "description": "<strong>Wh-word + było/było + podmiot + istota + V3?</strong>",
            "examples": [
                {
                    "en": "What was being built there?",
                    "ua": "Co tam zbudowano?"
                },
                {
                    "en": "Why was the road being closed?",
                    "ua": "Dlaczego droga była zablokowana?"
                },
                {
                    "en": "Where were the tests being conducted?",
                    "ua": "Gdzie przeprowadzono testy?"
                },
                {
                    "en": "How was the problem being solved?",
                    "ua": "Jak rozwiązałeś problem?"
                }
            ]
        },
        {
            "label": "Krótkie odpowiedzi",
            "color": "amber",
            "description": "Odpowiedzi zawierające <strong>Tak/Nie + zaimek + was/were (not)</strong>:",
            "examples": [
                {
                    "en": "Was the car being repaired? — Yes, it was. / No, it wasn't.",
                    "ua": "Czy samochód został naprawiony? - Tak. / NIE."
                },
                {
                    "en": "Were they being interviewed? — Yes, they were. / No, they weren't.",
                    "ua": "Czy przeprowadzono z nimi wywiad? - Tak. / NIE."
                }
            ]
        }
    ]
}

{
    "title": "6. Porównanie czasu aktywnego i pasywnego w czasie przeszłym ciągłym",
    "intro": "Jak zamienić zdanie czynne w stronę bierną:",
    "rows": [
        {
            "en": "Active: They were painting the house.",
            "ua": "Malowali dom.",
            "note": "→ Passive: The house was being painted."
        },
        {
            "en": "Active: The manager was checking the documents.",
            "ua": "Kierownik sprawdził dokumenty.",
            "note": "→ Passive: The documents were being checked."
        },
        {
            "en": "Active: Workers were repairing the road.",
            "ua": "Robotnicy naprawiali drogę.",
            "note": "→ Passive: The road was being repaired."
        },
        {
            "en": "Active: Someone was interviewing me.",
            "ua": "Ktoś przeprowadził ze mną wywiad.",
            "note": "→ Passive: I was being interviewed."
        }
    ],
    "warning": "📌 Znaczniki czasu (kiedy, kiedy, w tym czasie) pozostają!"
}

{
    "title": "7. Czas przeszły prosty pasywny a czas przeszły ciągły pasywny",
    "intro": "Porównanie dwóch form — działanie zakończone i działanie ciągłe:",
    "rows": [
        {
            "en": "The house was built in 1990.",
            "ua": "Dom został wybudowany w 1990 roku.",
            "note": "vs: Kiedy odwiedziłem, dom był w budowie. – Kiedy przyjechałem, dom był w budowie."
        },
        {
            "en": "The car was repaired yesterday.",
            "ua": "Wczoraj samochód został naprawiony.",
            "note": "vs: Samochód był naprawiany o godzinie 17:00. — Samochód był naprawiany o godzinie 17:00."
        },
        {
            "en": "The report was written.",
            "ua": "Raport został napisany.",
            "note": "vs: Raport był pisany przez cały dzień. - Raport był pisany przez cały dzień."
        }
    ],
    "warning": "📌 Past Simple = fakt, czynność zakończona. Past Continuous = proces, ciągłe działanie."
}

{
    "title": "8. Znaczniki czasu dla Past Continuous Passive",
    "intro": "Typowe słowa i wyrażenia wskazujące na Past Continuous:",
    "items": [
        {
            "label": "Moment",
            "title": "o 17:00, czyli o tej porze w południe",
            "subtitle": "Raport był pisany o godzinie 17:00."
        },
        {
            "label": "Przerywać",
            "title": "kiedy, podczas gdy, jako",
            "subtitle": "Kiedy zaczął padać deszcz, dom był malowany."
        },
        {
            "label": "Czas trwania",
            "title": "cały dzień, cały poranek, cały tydzień",
            "subtitle": "Droga była naprawiana przez cały tydzień."
        },
        {
            "label": "Równoległość",
            "title": "podczas gdy w tym samym czasie",
            "subtitle": "Kiedy czekaliśmy, obiad był przygotowywany."
        }
    ]
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak being.",
            "wrong": "The house was painted when I arrived.",
            "right": "✅ The house was being painted when I arrived."
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "Nieprawidłowy szyk.",
            "wrong": "The report being was written.",
            "right": "✅ The report was being written."
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "Mylenie been i being.",
            "wrong": "The car was been repaired.",
            "right": "✅ The car was being repaired."
        },
        {
            "label": "Błąd 4",
            "color": "rose",
            "title": "Mylenie Past Simple Passive i Past Continuous Passive.",
            "wrong": "The house was being built in 1990. (gdy chodzi o sam fakt)",
            "right": "✅ The house was built in 1990."
        }
    ]
}
